"city": "Dallas", "state": "TX", "summary": "Girls'' discipleship ministry focused on identity in Christ and biblical womanhood for middle and high school girls", "fit_score": 8, "fit_reason": "Active online ministry with speaking tours and curriculum sales indicating fundraising model", "source_query": "Wave 2 Hunter Research", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "Redeeming the Dirt", "org_type": "ministry", "website": "redeemingthedirt.com", "city": null, "state": null, "summary": "Ministry equipping Christians to connect faith and farming through training and resources. Mission: Live for Jesus, Excel in Agriculture, Make Disciples. Provides agricultural education and faith integration resources.", "fit_score": 8, "fit_reason": "Dedicated to Christian farming discipleship with clear mission statement. Offers training resources connecting faith and agriculture, reaching Christian farmers nationally.", "source_query": "Christian farming ministries sustainable agriculture faith-based", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "ReGeneration Ministries", "org_type": "ministry", "website": "regenerationministries.org", "city": "San Diego", "state": "CA", "summary": "Christian mentoring organization specializing in intergenerational faith development and legacy discipleship programs connecting experienced believers with younger generations.", "fit_score": 8, "fit_reason": "Explicit intergenerational ministry focus with giving page, prayer letter updates, active donor solicitation for mentoring program expansion", "source_query": "Wave 2 Hunter Research", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "Rights, Faith & Democracy Collaborative", "org_type": "ministry", "website": "www.proteusfund.org/rfdc", "city": null, "state": null, "summary": "Initiative of Proteus Fund educating and mobilizing philanthropy to support diverse coalitions of state-based activists and organizations at intersections of faith and queer, gender, and racial justice. One of few donor collaboratives dedicated to faith-justice intersectional work.", "fit_score": 8, "fit_reason": "Unique funder collaborative with documented mission to raise and target resources for faith-justice work. Direct connection to philanthropic funding infrastructure and donor networks. Strategic position in faith-based justice funding landscape.", "source_query": "faith-based civil rights organizations donor support infrastructure", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "San Antonio Pregnancy Care Center", "org_type": "ministry", "website": "sapregnancy.org", "city": "San Antonio", "state": "TX", "summary": "Christian pregnancy resource center providing free ultrasounds, pregnancy tests, and mentoring to women facing unplanned pregnancies. Aims to promote adoption and parenting alternatives.", "fit_score": 8, "fit_reason": "Local pregnancy center with established web presence and community engagement. Part of ecosystem of pregnancy centers using standardized fundraising platforms and donor engagement strategies.", "source_query": "Wave 2 Hunter Research", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "Save The Storks", "org_type": "ministry", "website": "savethestorks.com", "city": "Knoxville", "state": "TN", "summary": "Christian pro-life ministry providing ultrasound equipment and training to pregnancy support centers to empower women to choose life.", "fit_score": 8, "fit_reason": "Clear mission-driven giving platform, founder-led organization with active donor communications and fundraising for ultrasound equipment donation programs", "source_query": "Wave 2 Hunter Research", "meta": {"import_source": "FINAL_CONSOLIDATED_ALL_WAVES.json"}}, {"org_name": "Sean Feucht", "org_type": "ministry", "website": "seanfeucht.com", "city": "Redding", "state": "CA", "summary": "Worship leader and recording artist;